import{_ as o,o as t,c as s,Q as a}from"./chunks/framework.b6910bb2.js";const r="/vitePress-blob/assets/15.27ac4bfa.png",n="/vitePress-blob/assets/14.b6316457.png",b=JSON.parse('{"title":"Claude Code 技术全景概览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai/Claude Code 技术全景概览.md","filePath":"guide/ai/Claude Code 技术全景概览.md","lastUpdated":1773825789000}'),e={name:"guide/ai/Claude Code 技术全景概览.md"},l=a('<h1 id="claude-code-技术全景概览" tabindex="-1">Claude Code 技术全景概览 <a class="header-anchor" href="#claude-code-技术全景概览" aria-label="Permalink to &quot;Claude Code 技术全景概览&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>随着 Vibe Coding 的普及，Claude Code 正逐渐走进开发者视野。深入理解 Claude Code，有助于我们更好地运用 Vibe Coding，显著提升研发效率。</p><p>本文作为 Claude Code 专栏系列的第一讲，将从全景视角，为你系统解析 Claude Code 的设计理念与整体架构。</p><h2 id="技术全览图" tabindex="-1">技术全览图 <a class="header-anchor" href="#技术全览图" aria-label="Permalink to &quot;技术全览图&quot;">​</a></h2><p>整体可划分为四层：<strong>基础层</strong>、<strong>拓展层</strong>、<strong>集成层</strong>、<strong>编程接口层</strong>，从下到上依次体现记忆与知识、能力扩展、对外集成与编程控制。</p><h2 id="" tabindex="-1"><img src="'+r+'" alt="Claude Code 底层技术全景图"> <a class="header-anchor" href="#" aria-label="Permalink to &quot;![Claude Code 底层技术全景图](./../../public/assets/ai/15.png)&quot;">​</a></h2><h3 id="基础层" tabindex="-1">基础层 <a class="header-anchor" href="#基础层" aria-label="Permalink to &quot;基础层&quot;">​</a></h3><p>基础层包含 <strong>Memory（记忆系统）</strong>，通常是一个 <strong>CLAUDE.md</strong> 文件，作用类似 Cursor 的 Cursor Rule，相当于项目的「手册」：约定技术栈、目录结构、提交规范、编码习惯等，让 Claude 在对话中始终遵循同一套上下文与规范。</p><hr><h3 id="拓展层" tabindex="-1">拓展层 <a class="header-anchor" href="#拓展层" aria-label="Permalink to &quot;拓展层&quot;">​</a></h3><p>拓展层包含四大核心组件：<strong>Commands（手动触发）</strong>、<strong>Skills（自主发现）</strong>、<strong>SubAgents（任务分发）</strong>、<strong>Hooks（事件驱动）</strong>，对应 Agent 执行与感知任务的四种方式。</p><h4 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h4><ul><li><strong>Commands</strong> 适合<strong>标准化、可重复</strong>的操作，例如：git commit 格式、固定部署流程、固定代码检查命令等。由用户通过固定关键词或指令显式触发，执行相对固化的标准流程。</li></ul><h4 id="subagents" tabindex="-1">SubAgents <a class="header-anchor" href="#subagents" aria-label="Permalink to &quot;SubAgents&quot;">​</a></h4><ul><li><strong>SubAgents</strong> 适合<strong>隔离执行</strong>的任务，例如：从大量日志中筛选错误日志、在独立上下文中跑测试、做单一步骤的代码分析等。减少主 Agent 的上下文与职责膨胀，保证主会话聚焦、子任务边界清晰。</li></ul><h4 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h4><ul><li><p><strong>Skills</strong> 是可被<strong>语义化加载</strong>的技能包：不依赖固定关键词，Claude 会根据当前对话与任务上下文判断是否需要调用某个 Skill，从而<strong>自主编排</strong>何时用哪项能力。</p></li><li><p><strong>Skill 和 MCP 的区别</strong></p><ul><li><strong>MCP</strong> 解决的是「大模型与外部世界如何交互」：调用 API、读库、执行命令等。</li><li><strong>Skills</strong> 解决的是「大模型该如何执行任务」：约束步骤、规范、决策方式，是执行策略与工作流层面的能力。</li></ul></li><li><p><strong>Command 和 Skill 的区别</strong></p><ul><li><strong>Commands</strong>：依赖固定关键词或指令，<strong>显式触发</strong>，适合可复用、相对固化的标准流程。</li><li><strong>Skills</strong>：依赖<strong>上下文</strong>而非固定关键词，由模型判断是否适用并决定如何执行，适合「在合适场景下自动用上」的能力。</li></ul></li></ul><p>SubAgents 与 Skills 的出现，都是为了应对单一 Agent 在<strong>上下文、权限、职责</strong>无法无限膨胀的问题。更重要的是，Skill 带来的重要变化是：从<strong>人类预先编排工作流</strong>，转向 <strong>Agent 根据上下文自主编排工作流</strong>。</p><h4 id="hooks" tabindex="-1">Hooks <a class="header-anchor" href="#hooks" aria-label="Permalink to &quot;Hooks&quot;">​</a></h4><ul><li><strong>Hooks</strong> 是在<strong>特定事件</strong>发生时自动触发的钩子，例如：在每次工具执行前后做检查、在会话开始时加载规则、在提交前做校验等，实现事件驱动的自动化行为。</li></ul><hr><h3 id="集成层" tabindex="-1">集成层 <a class="header-anchor" href="#集成层" aria-label="Permalink to &quot;集成层&quot;">​</a></h3><p>集成层包含：</p><ul><li><strong>Headless</strong>：与 <strong>CI/CD</strong> 集成，在流水线中无界面、脚本化地调用 Claude Code 能力。</li><li><strong>MCP（Model Context Protocol）</strong>：连接<strong>外部工具与系统</strong>（数据库、API、内部服务等），扩展 Agent 可调用的能力边界。</li></ul><hr><h3 id="编程接口层" tabindex="-1">编程接口层 <a class="header-anchor" href="#编程接口层" aria-label="Permalink to &quot;编程接口层&quot;">​</a></h3><p>编程接口层包含 <strong>Agent SDK</strong>（如 Python / TypeScript），提供<strong>编程式控制 Agent、编排工作流</strong>的能力，适合需要完全由代码驱动、与现有系统深度集成的场景。</p><hr><h2 id="如何抉择" tabindex="-1">如何抉择 <a class="header-anchor" href="#如何抉择" aria-label="Permalink to &quot;如何抉择&quot;">​</a></h2><p>当你在「用哪种方式用」之间做选择时，可以按下面流程判断：是「需要 Claude 具备某种能力」，还是「需要隔离/事件/集成/编程控制」等非能力型需求，再对应到 Commands、Skills、SubAgents、Hooks、MCP、Headless 或 Agent SDK。</p><p><img src="'+n+'" alt="需要 Claude 具备某种能力？—— 抉择流程图"></p><ul><li><strong>需要某种能力且希望用户手动触发</strong> → 选 <strong>Commands</strong>。</li><li><strong>需要某种能力且希望 Claude 自动识别、按上下文执行</strong> → 选 <strong>Skills</strong>。</li><li><strong>需要隔离执行或控制上下文/职责</strong> → 选 <strong>SubAgents</strong>。</li><li><strong>需要在工具执行等事件时自动检查或执行逻辑</strong> → 选 <strong>Hooks</strong>。</li><li><strong>需要连接外部系统、数据源或工具</strong> → 选 <strong>MCP</strong>。</li><li><strong>需要在 CI/CD 中集成</strong> → 选 <strong>Headless</strong>。</li><li><strong>需要完全由代码编排与控制 Agent</strong> → 选 <strong>Agent SDK</strong>。</li></ul><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>这篇文章介绍了 Claude Code 的技术全景与选型思路：从基础记忆到拓展能力，再到集成与编程接口，按需求对号入座即可做出清晰抉择。</p>',36),i=[l];function g(d,u,h,c,C,m){return t(),s("div",null,i)}const k=o(e,[["render",g]]);export{b as __pageData,k as default};
